INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (309, 8, 0, 0.5, 309019, 103811, "あのお料理美味しそう……\nお姉ちゃんにも教えてあげなくちゃ。", 0, 11, 0, 0);
