INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311, 8, 0, 0.5, 311002, 102711, "この広い会場のどこかに\nあのおかたの存在を感じますわ……", 0, 11, 0, 0);
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311, "", "", "", 311003, 311002, "", "", 91, "", "");
