INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311, 8, 0, 0.5, 311006, 100911, "疼く……疼くぞ！\n我が魔眼が新たなる年を祝えと……！", 0, 11, 0, 0);
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (311, "", "", "", 311007, 311006, "", "", 91, "", "");
