INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312, 8, 0, 0.5, 312001, 101831, "素敵な新年会ね～\n他の学校の人たちも来ているようだし\nお話を伺いに行こうかしら？", 0, 11, 0, 0);
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312, 1, 0.2, "", 312002, 101831, "nop_talk_joy1", "", 3, "", "");
