INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312, 1, 0.2, "", 312004, 101831, "nop_idle_joy1", 1, 3, "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312, 8, 0, 0.5, 312005, 101611, "見て見てミサキっち！\nあそこの料理すっごく美味しそう！", 0, 11, 0, 0);
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312, 1, 0.2, "", 312006, 101611, "nop_talk_surprise_kira", "", 3, "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312, "", "", "", 312007, 312005, "", "", 91, "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312, 1, 0.2, "", 312008, 101611, "nop_idle_surprise_kira", 1, 3, "", "");
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312, 8, 0, 0.5, 312009, 105011, "えー？　でもあれって野菜じゃない？\n別に、大人のレディだから\n食べられないわけじゃないけど？", 0, 11, 0, 0);
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (312, 1, 0.2, "", 312010, 105011, "nop_talk_sad", "", 3, "", "");
