INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (313, 8, 0, 0.5, 313001, 105331, "立派な新年会ではないか。\n我々もこの場に相応しく\n振る舞わなければな！", 0, 11, 0, 0);
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (313, 0, 0.2, "", 313002, 105331, "nop_13_monica_talk_doya", 1, 3, 0.2, "nop_13_monica_talk_doya_loop");
