INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (506, 1, 0.2, "", 506014, 103731, "nop_06_tomo_talk_anger", "", 3, "", "");
