INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (506, 8, 0, 0.5, 506018, 104731, "まあまあ、\nトモちゃんもクリスちゃんも。\nせっかくの新年会なんだから……", 0, 11, 0, 1);
INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (506, 1, 0.2, "", 506019, 104731, "nop_talk_normal", "", 3, "", "");
