INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (506, 8, 0, 0.5, 506023, 100511, "そうッス！\n美味しい料理もいっぱいだし、\n楽しまなくっちゃ損ッスよ！", 0, 11, 0, 1);
