INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (513, 1, 0.2, "", 513068, 104511, "nop_13_kuka_talk_memory2", "", 3, "", "");
