INSERT INTO `v1_3dd90e8783e78d32eadcb6dac5d4ce343328bdd13443465fd3b309cb0e8cc861` VALUES (513, 6, 0, 0.5, 513077, 105331, "新年といういい機会だ。\n今年の抱負を発表しようじゃないか。", 0, 11, 0, 1);
